#include "interface.h"

#include <rapidjson/writer.h>
#include <rapidjson/stringbuffer.h>

std::string build_json(
    const std::vector<uint32_t>& ids,
    const std::vector<uint32_t>& values,
    const std::vector<std::string>& names) {
  rapidjson::StringBuffer buffer;
  // Small-batch workload: reserve a modest amount to reduce reallocations.
  // Approximate per-record payload plus brackets/commas.
  const std::size_t n = ids.size();
  std::size_t estimated = 2;  // [ ]
  for (std::size_t i = 0; i < n; ++i) {
    estimated += 40 + names[i].size();
  }
  buffer.Reserve(static_cast<rapidjson::SizeType>(estimated));

  rapidjson::Writer<rapidjson::StringBuffer> writer(buffer);
  writer.StartArray();
  for (std::size_t i = 0; i < n; ++i) {
    writer.StartObject();

    writer.Key("id", 2);
    writer.Uint(ids[i]);

    writer.Key("flag", 4);
    writer.Bool((ids[i] % 3U) == 0U);

    writer.Key("value", 5);
    writer.Uint(values[i]);

    writer.Key("name", 4);
    writer.String(names[i].data(), static_cast<rapidjson::SizeType>(names[i].size()));

    writer.EndObject();
  }
  writer.EndArray();

  return std::string(buffer.GetString(), buffer.GetSize());
}
